# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
import os
import logging

app = Flask(__name__)

# Initialize Elasticsearch client
es = Elasticsearch(
    hosts=[os.getenv('ES_HOST', 'localhost:9200')],
    timeout=30,
    max_retries=10,
    retry_on_timeout=True
)

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

@app.route('/api/search', methods=['GET'])
def search_products():
    try:
        # Get query parameter
        query = request.args.get('q', '').strip()
        
        # Validate query
        if not query:
            return jsonify({'error': 'Query parameter "q" is required'}), 400
        
        # Build Elasticsearch query
        search_body = {
            "query": {
                "bool": {
                    "should": [
                        {
                            "multi_match": {
                                "query": query,
                                "type": "bool_prefix",
                                "fields": ["name^2", "description", "tags"],
                                "boost": 1.0
                            }
                        },
                        {
                            "wildcard": {
                                "name": f"*{query}*"
                            }
                        }
                    ],
                    "minimum_should_match": 1
                }
            },
            "size": 100,
            "highlight": {
                "fields": {
                    "name": {},
                    "description": {}
                }
            }
        }
        
        # Execute search
        response = es.search(
            index="products",
            body=search_body,
            request_cache=True
        )
        
        # Process results
        products = []
        for hit in response['hits']['hits']:
            product = {
                'id': hit['_id'],
                'name': hit['_source'].get('name', ''),
                'description': hit['_source'].get('description', ''),
                'price': hit['_source'].get('price', 0),
                'tags': hit['_source'].get('tags', []),
                'highlight': hit.get('highlight', {})
            }
            products.append(product)
        
        return jsonify({
            'query': query,
            'total': response['hits']['total']['value'],
            'products': products
        })
        
    except Exception as e:
        logger.error(f"Search error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, threaded=True)